	for i := range visited {
		visited[i] = make([]bool, n)
	}

	result := int64(0)

	for i := 0; i < m; i++ {
		for j := 0; j < n; j++ {
			if grid[i][j] != 0 && !visited[i][j] {
				// Perform BFS to find the island
				queue := list.New()
				queue.PushBack(image.Pt(j, i))
				visited[i][j] = true
				total := int64(grid[i][j])
				// Keep track of the remainder of the island value modulo k
				remainder := int64(grid[i][j]) % k

				for queue.Len() > 0 {
					pt := queue.Front()
					queue.Remove(pt)
					x := pt.Value.(image.Pt).X
					y := pt.Value.(image.Pt).Y

					// Check all four directions
					for _, dx := range []int{-1, 0, 1} {
						for _, dy := range []int{-1, 0, 1} {
							if dx == 0 && dy == 0 {
								continue
							}
							ny := y + dy
							nx := x + dx
							if nx >= 0 && nx < n && ny >= 0 && ny < m && !visited[ny][nx] && grid[ny][nx] != 0 {
								visited[ny][nx] = true
								queue.PushBack(image.Pt(nx, ny))
								total += grid[ny][nx]
								remainder = (remainder + grid[ny][nx]) % k
							}
						}
					}
				}

				// Check if the total value is divisible by k
				if remainder == 0 {
					result++
				}
			}
