type Point struct {
	x, y int
}

type Queue []Point

func (q Queue) Len() int { return len(q) }

func (q Queue) Less(i, j int) bool { return q[i].x < q[j].x || (q[i].x == q[j].x && q[i].y < q[j].y) }
func (q Queue) Swap(i, j int) { q[i], q[j] = q[j], q[i] }

func (q *Queue) Push(x interface{}) {
	*q = append(*q, x.(Point))
}

func (q *Queue) Pop() interface{} {
	old := *q
	n := len(old)
	*q = old[0 : n-1]
	return old[n-1]
}

func solve(grid [][]int64, k int64) int64 {
	m := len(grid)
	n := len(grid[0])
	visited := make([][]bool, m)
	for i := range visited {
		visited[i] = make([]bool, n)
	}
	result := int64(0)

	for i := 0; i < m; i++ {
		for j := 0; j < n; j++ {
			if grid[i][j] > 0 && !visited[i][j] {
				// Perform BFS to find the island
				queue := make(Queue, 0)
				queue = append(queue, Point{i, j})
				visited[i][j] = true
				total := int64(grid[i][j])
				// Use a map to store the remainder of the sum modulo k
				remainderMap := make(map[int64]int64)
				remainderMap[total%k] = 1
				for queue.Len() > 0 {
					p := heap.Pop(&queue).(Point)
					x, y := p.x, p.y
					for _, dir := range []Point{{-1, 0}, {1, 0}, {0, -1}, {0, 1}} {
						newX, newY := x+dir.x, y+dir.y
						if newX >= 0 && newX < m && newY >= 0 && newY < n && !visited[newX][newY] && grid[newX][newY] > 0 {
							visited[newX][newY] = true
							total += int64(grid[newX][newY])
							heap.Push(&queue, Point{newX, newY})
							// Update the remainder map
							remainder := total % k
							remainderMap[remainder] += 1
						}
					}
				}
				// Count how many islands have a sum divisible by k
				result += remainderMap[0]
			}
		}
	}
	return result
